import combos from "../../data-json/combos.json"
import Tarjeta from '../tarjetas-simple-doble/tarjeta.jsx';

 function Combos( setCarrito, carrito ) {
  
  const agregarAlCarrito = () => {
    setCarrito({ ...carrito, elemento})
    console.log(carrito)
  }
  
  
  return (
    <div className='productos-cont'>

      <h2 id='combos'>COMBOS</h2>

      <div className='combos'>
        {
          combos &&
          combos.map((elemento) => (
            <Tarjeta key={elemento.id} elemento={elemento} id={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} descripcion={elemento.descripcion} setCarrito={setCarrito} carrito={carrito} agregarAlCarrito={agregarAlCarrito} />
          ))
        }
      </div>

    </div>
  )
};
 



export default Combos;
